    'likeVideo' : IDL.Func([VideoId], [IDL.Bool], []),
    'listBlogs' : IDL.Func([ListBlogsQuery], [ListBlogsResult], ['query']),
    'listConversations' : IDL.Func([], [IDL.Vec(Conversation)], []),
    'listNotes' : IDL.Func([NoteListQuery], [NoteListResult], ['query']),
    'listNotifications' : IDL.Func([], [ListNotificationsResult], []),
    'listVideos' : IDL.Func([VideoFilter], [VideoPage], ['query']),
