    'sendMessage' : IDL.Func([IDL.Nat, IDL.Text], [SendMessageResult], []),
    'transform' : IDL.Func(
        [TransformationInput],
        [TransformationOutput],
        ['query'],
      ),
    'unbookmarkBlog' : IDL.Func([BlogId], [], []),
    'unbookmarkNote' : IDL.Func([IDL.Nat], [], []),
    'unbookmarkVideo' : IDL.Func([VideoId], [IDL.Bool], []),
    'unlikeBlog' : IDL.Func([BlogId], [], []),
    'unlikeNote' : IDL.Func([IDL.Nat], [], []),
